   121→// Convert golang errors to status result errors that can be returned to a client
   122→func AsErrorResult(err error) *resourcepb.ErrorResult {
   123→	if err == nil {
   124→		return nil
   125→	}
   126→
   127→	var apistatus apierrors.APIStatus
   128→	if errors.As(err, &apistatus) {
   129→		s := apistatus.Status()
   130→		res := &resourcepb.ErrorResult{
   131→			Message: s.Message,
   132→			Reason:  string(s.Reason),
   133→			Code:    s.Code,
   134→		}
   135→		if s.Details != nil {
   136→			res.Details = &resourcepb.ErrorDetails{
   137→				Group:             s.Details.Group,
   138→				Kind:              s.Details.Kind,
   139→				Name:              s.Details.Name,
   140→				Uid:               string(s.Details.UID),
   141→				RetryAfterSeconds: s.Details.RetryAfterSeconds,
   142→			}
   143→			for _, c := range s.Details.Causes {
   144→				res.Details.Causes = append(res.Details.Causes, &resourcepb.ErrorCause{
   145→					Reason:  string(c.Type),
   146→					Message: c.Message,
   147→					Field:   c.Field,
   148→				})
   149→			}
   150→		}
   151→		return res
   152→	}
   153→
   154→	code := 500
   155→
   156→	st, ok := grpcstatus.FromError(err)
   157→	if ok {
   158→		code = runtime.HTTPStatusFromCode(st.Code())
   159→	}
   160→
   161→	return &resourcepb.ErrorResult{
   162→		Message: err.Error(),
   163→		Code:    int32(code),
   164→	}
   165→}
   166→
   167→func GetError(res *resourcepb.ErrorResult) error {
   168→	if res == nil {
   169→		return nil
   170→	}
   171→
   172→	status := &apierrors.StatusError{ErrStatus: metav1.Status{
   173→		Status:  metav1.StatusFailure,
   174→		Code:    res.Code,
   175→		Reason:  metav1.StatusReason(res.Reason),
   176→		Message: res.Message,
   177→	}}
   178→	if res.Details != nil {
   179→		status.ErrStatus.Details = &metav1.StatusDetails{
   180→			Group:             res.Details.Group,
   181→			Kind:              res.Details.Kind,
   182→			Name:              res.Details.Name,
   183→			UID:               types.UID(res.Details.Uid),
   184→			RetryAfterSeconds: res.Details.RetryAfterSeconds,
   185→		}
   186→		for _, c := range res.Details.Causes {
   187→			status.ErrStatus.Details.Causes = append(status.ErrStatus.Details.Causes, metav1.StatusCause{
   188→				Type:    metav1.CauseType(c.Reason),
   189→				Message: c.Message,
   190→				Field:   c.Field,
   191→			})
   192→		}
   193→	}
   194→	return status
   195→}
